            controller: controller,
            autofocus: true,
            decoration: const InputDecoration.collapsed(
              hintText: 'Hint text',
              filled: true,
              border: UnderlineInputBorder(),
            ),
          ),
        ),
      ),
    );
  }

  @override
  void dispose() {
    controller.dispose();
    super.dispose();
  }
}

```

